#include<cstdio>
#include<cstdlib>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void Swap(int &x,int &y){int tmp=x;x=y;y=tmp;}
inline long long Max(long long x,long long y){return x>y?x:y;}
const int N=1e5+10;
struct {int l,r,val,siz;long long sm;short key;}t[N*100];int Rt[N],cnt,T1,T2;
int head[N],des[N],nxt[N],cgt,n,cst[N],ldr[N];long long ans=0;int M;
inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
inline int Node(int x){t[++cnt].siz=1;t[cnt].sm=t[cnt].val=x;t[cnt].key=rand();return cnt;}
inline void update(int k)
{
	t[k].siz=t[t[k].l].siz+t[t[k].r].siz+1;
	t[k].sm=t[t[k].l].sm+t[t[k].r].sm+t[k].val;
}
inline void split(int cur,int k,int &x,int &y)
{
	if(!cur){x=y=0;return;}
	if(t[cur].val<=k)x=cur,split(t[cur].r,k,t[cur].r,y);
	else y=cur,split(t[cur].l,k,x,t[cur].l);update(cur);
}
inline int merge(int x,int y)
{
	if(!x||!y)return x|y;
	if(t[x].key<t[y].key)return t[x].r=merge(t[x].r,y),update(x),x;
	return t[y].l=merge(x,t[y].l),update(y),y;
}
int RTT;inline void Dfs(int cur)
{
	if(!cur)return;Dfs(t[cur].l);
	split(RTT,t[cur].val,T1,T2);
	int rr=t[cur].r;t[cur].l=t[cur].r=0;t[cur].siz=1;t[cur].key=rand();t[cur].sm=t[cur].val;
	RTT=merge(merge(T1,cur),T2);Dfs(rr);
}
inline int Merge(int x,int y){if(t[x].siz<t[y].siz)Swap(x,y);RTT=x;Dfs(y);return RTT;}
inline int fnd(int x,int sum=M)
{
	if(!x)return 0;if(t[t[x].l].sm>sum)return fnd(t[x].l,sum);
	if(t[t[x].l].sm+t[x].val>sum)return t[t[x].l].siz;
	return fnd(t[x].r,sum-t[t[x].l].sm-t[x].val)+t[t[x].l].siz+1;
}
inline void dfs(int u)
{
	Rt[u]=Node(cst[u]);
	grep(u,i){dfs(des[i]);Rt[u]=Merge(Rt[u],Rt[des[i]]);}
	ans=Max(ans,1ll*fnd(Rt[u])*ldr[u]);
}
int main()
{
	srand(19260817);t[0].siz=0;
	n=read();M=read();read();cst[1]=read();ldr[1]=read();
	rep(2,n,i){ins(read(),i);cst[i]=read();ldr[i]=read();}
	dfs(1);printf("%lld\n",ans);return 0;
}
